1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] -> []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] -> []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (each has 1 neighbor) — [(0,1),(1,1)] -> []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] -> same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with 4+ neighbors dies (overpopulation) — center of full 3x3 dies", () => {
21	    const fullSquare: Cell[] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1], [2, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const result = nextGeneration(fullSquare);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape produces block", () => {
30	    const lShape: Cell[] = [[0, 0], [1, 0], [0, 1]];
31	    const expectedBlock: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(lShape);
33	    expect(result).toHaveLength(4);
34	    expect(result).toEqual(expect.arrayContaining(expectedBlock));
35	  });
36	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]", () => {
37	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
38	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
39	    const result = nextGeneration(vertical);
40	    expect(result).toHaveLength(3);
41	    expect(result).toEqual(expect.arrayContaining(horizontal));
42	  });
43	  it("blinker oscillates back from horizontal to vertical — [(-1,1),(0,1),(1,1)] -> [(0,0),(0,1),(0,2)]", () => {
44	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
45	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
46	    const result = nextGeneration(horizontal);
47	    expect(result).toHaveLength(3);
48	    expect(result).toEqual(expect.arrayContaining(vertical));
49	  });
