51	    const verticalAtNegative: Cell[] = [[-5, -5], [-5, -4], [-5, -3]];
52	    const expectedHorizontal: Cell[] = [[-6, -4], [-5, -4], [-4, -4]];
53	    const result = nextGeneration(verticalAtNegative);
